INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (35, "", 24001, 1, "", 0, 2, 0, 30000, 0, 15);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (36, "", 91002, 100, "", 0, 8, 0, 40000, 0, 1);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (37, "ぺコリーヌ", 91002, 150, "今日は記念日、お祝いですね！\n焼肉、お寿司、ピザ、ケーキ～☆\nあなたとパーティできるなんて、\n幸せです～♪", 107501, 8, 1, 40001, 0, 1);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (38, "コッコロ", 91002, 150, "この記念日を迎えられたのは、\n主さまの器量の賜物\nさすがは主さまでございます\nえらい、えらい♪", 107601, 8, 1, 40001, 0, 2);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (39, "キャル", 91002, 150, "あんたもけっこうやるじゃない！\nちょっとは…割と…け、けっこう\n見直しちゃったわ\n褒めてあげる♪", 107801, 8, 1, 40001, 0, 3);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40, "スズメ", 91002, 150, "あなたと私にとって、\n今日は特別な日\nあなたの支えがあるから、\n私は頑張れるんです！", 107701, 8, 1, 40001, 0, 4);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (41, "タマキ", 91002, 150, "今日はキミにとっての\n特別な記念日だにゃ\nキミの活躍にはいつも\n猫ながら感謝してるにゃ～♪", 107901, 8, 1, 40001, 0, 5);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (42, "ぺコリーヌ", 91002, 150, "う～かき氷食べ過ぎて、\n身体が冷えちゃいました…\nあなたの体温で温めてください！\nギューーッ♪", 107501, 8, 2, 40001, 0, 6);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (43, "コッコロ", 91002, 150, "夏は危険がいっぱいと申します…\nですが、わたくしが主さまを\nしっかりとお守りいたしますよ", 107601, 8, 2, 40001, 0, 7);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (44, "キャル", 91002, 150, "ん～なんであんたと、ひと夏を\n過ごすことになったのかな…\n結構楽しいからいいけど！\nさ、まだまだ遊ぶわよ！", 107801, 8, 2, 40001, 0, 8);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (45, "スズメ", 91002, 150, "あなたと過ごすはじめての夏…\nいまからドキドキが止まりません\n楽しくて素敵な思い出が、\nまた一つ増えるんですね♪", 107701, 8, 2, 40001, 0, 9);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (46, "タマキ", 91002, 150, "夏は一番の稼ぎ時にゃのに、\n今年はキミと過ごしたいって\n思ってるにゃ楽しい思い出\n増やしてくれるかにゃ？", 107901, 8, 2, 40001, 0, 10);
