INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (320, "", 23001, 20, "", 0, 2, 0, 20001, 0, 10);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (321, "リリ", 24001, 1, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 125801, 2, 1, 40011, 0, 1);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (322, "クリア", 24001, 1, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 126001, 2, 1, 40011, 0, 2);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (323, "プレシア", 24001, 1, "んーと。\nこれ、あげる。\nはい", 126101, 2, 1, 40011, 0, 3);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (324, "リリ", 24001, 1, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 125801, 2, 2, 40011, 0, 4);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (325, "クリア", 24001, 1, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 126001, 2, 2, 40011, 0, 5);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (326, "プレシア", 24001, 1, "お兄。\nきてくれて、うれしい", 126101, 2, 2, 40011, 0, 6);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (327, "", 91002, 100, "", 0, 8, 0, 80009, 532001, 1);
